-- Дополнение: автоматически сформировать ещё ~600 карточек по темам
do $$
declare
  topics text[] := array[
    'Налоги', 'Банковское дело', 'Инвестиции', 'Бюджет', 'Страхование',
    'Кредитование', 'Предпринимательство', 'Личные финансы', 'Финтех', 'Госпрограммы'
  ];
  complexities text[] := array['easy', 'medium', 'hard'];
  i int;
  topic text;
  diff text;
begin
  for i in 1..600 loop
    topic := topics[1 + (i - 1) % array_length(topics)];
    diff := complexities[1 + (i - 1) % array_length(complexities)];
    insert into training_cards (category, question, answer, difficulty, created_at)
    values (
      topic,
      format('Сценарная задача #%s по теме %s: разберите финансовую ситуацию.', i, topic),
      format('Подготовьте детальный разбор сценария #%s по теме %s. Определите риски, предложите шаги и связанные показатели.', i, topic),
      diff,
      now() - (i || ' days')::interval
    );
  end loop;
end
$$;

