-- Дополнение: сгенерировать ещё 120 теоретических блоков
do $$
declare
  base_topics text[] := array[
    'tax', 'budget', 'credit', 'insurance', 'investment',
    'entrepreneur', 'family', 'education', 'fintech', 'digital'
  ];
  idx int;
  suffix text;
  topic text;
begin
  for idx in 1..120 loop
    topic := base_topics[1 + (idx - 1) % array_length(base_topics)];
    suffix := lpad(idx::text, 3, '0');
    insert into theory (id, title, summary, content)
    values (
      format('%s-note-%s', topic, suffix),
      format('Расширенный модуль %s #%s', topic, suffix),
      format('Дополнительный конспект по теме %s: углубление и примеры.', topic),
      format('## Теория %s #%s\n- Определение\n- Ключевые формулы\n- Практические замечания\n\n### Примеры\n1. Сценарий обучения\n2. Расчёт показателей\n3. Контрольные вопросы', upper(topic), suffix)
    )
    on conflict (id) do nothing;
  end loop;
end
$$;

