-- Дополнение: сгенерировать 200 материалов базы знаний со ссылками на storage
do $$
declare
  categories text[] := array[
    'Налоги', 'Бюджет', 'Инвестиции', 'Страхование', 'Кредитование',
    'Предпринимательство', 'Финтех', 'Олимпиады', 'Образование', 'Психология'
  ];
  formats text[] := array['text', 'pdf', 'image', 'link'];
  diff text[] := array['easy', 'medium', 'hard'];
  i int;
  category text;
  f text;
  d text;
  id text;
begin
  for i in 1..200 loop
    category := categories[1 + (i - 1) % array_length(categories)];
    f := formats[1 + (i - 1) % array_length(formats)];
    d := diff[1 + (i - 1) % array_length(diff)];
    id := format('kb-auto-%s', lpad(i::text, 3, '0'));
    insert into knowledge_resources (id, category, title, description, type, url, content, difficulty, tags)
    values (
      id,
      category,
      format('%s: доп. материал #%s', category, lpad(i::text, 3, '0')),
      format('Автоматически сгенерированный материал по теме %s.', category),
      f,
      case f
        when 'pdf' then format('https://<project>.supabase.co/storage/v1/object/public/knowledge/auto/%s.pdf', id)
        when 'image' then format('https://<project>.supabase.co/storage/v1/object/public/knowledge/auto/%s.png', id)
        when 'link' then format('https://academy.project.ru/materials/%s', id)
        else null
      end,
      case f when 'text' then format('Содержимое материала #%s по теме %s.\n\n- Раздел 1\n- Раздел 2\n- Контрольные вопросы', i, category) else null end,
      d,
      array[ lower(replace(category, ' ', '_')), format('auto_%s', i) ]
    )
    on conflict (id) do nothing;
  end loop;
end
$$;

