insert into practice_cases (id, title, summary, prompt, solution, points, difficulty)
values
  ('case-budget-360', 'Антикризисный бюджет семьи', 'Адаптируйте бюджет при сокращении дохода на 25%.', 'Семья Соколовых тратила 210 000 ₽ при доходе 240 000 ₽. В апреле доход упал до 180 000 ₽. Составьте план сокращения расходов, сохраните платежи по ипотеке 45 000 ₽ и накопления 20 000 ₽.', '1. Пересмотр обязательных расходов (экономия 25 000 ₽)\n2. Перепланировка ипотечного платежа (каникулы на 2 месяца)\n3. Дополнительный доход: репетиторство 10 000 ₽\n4. Итоговый бюджет: 180 000 ₽ = расходы 140 000 ₽ + накопления 20 000 ₽ + резерв 20 000 ₽', 16, 'medium'),
  ('case-tax-matrix', 'Матрица налоговых вычетов', 'Определите стратегию вычетов для семьи с несколькими основаниями.', 'Марина потратила: 450 000 ₽ на обучение сына, 180 000 ₽ на лечение, купила квартиру за 5 млн ₽ и оформила ИИС на 400 000 ₽. Определите, как получить максимум налоговых возмещений.', '1. Социальные вычеты: 120 000 ₽ база (обучение + лечение) → 15 600 ₽ возврата.\n2. Имущественный вычет: 2 000 000 ₽ база → 260 000 ₽ возврата.\n3. Проценты по ипотеке (при наличии) до 390 000 ₽.\n4. ИИС тип А: 400 000 ₽ → 52 000 ₽ (если нет зарплаты - перенос).\n5. График подачи 3-НДФЛ и перенос остатка.', 18, 'hard'),
  ('case-invest-goal', 'Портфель для цели «Образование»', 'Сформируйте портфель на 7 лет для оплаты обучения ребёнка.', 'Цель — накопить 3,5 млн ₽ за 7 лет. Семья готова инвестировать регулярно и принимает умеренный риск. Предложите структуру портфеля и график взносов.', '1. Ежемесячный взнос: ~30 000 ₽ при ожидаемой доходности 10%.\n2. Портфель: 40% облигации, 40% акции (ETF РФ/США), 10% золото, 10% денежная подушка.\n3. Перебалансировка раз в год.\n4. Использование ИИС типа Б для освобождения прибыли.', 15, 'medium'),
  ('case-credit-dbt', 'Диагностика долговой нагрузки', 'Разработайте план выхода из долговой спирали.', 'У семьи три кредита (ипотека 6 млн ₽ под 9%, автокредит 800 тыс ₽ под 14%, потребкредит 300 тыс ₽ под 18%). Доход 220 тыс ₽. Определите PTI, предложите меры по снижению нагрузки.', '1. PTI = 42% — допустимо, но высокий риск.\n2. План: рефинансировать автокредит до 11%, закрыть потребкредит досрочно за счёт резерва.\n3. Создать подушку 150 тыс ₽.\n4. Вести учёт расходов, не брать новые кредиты.', 12, 'medium'),
  ('case-insurance-check', 'Страхование предпринимателя', 'Постройте программу страховок для ИП.', 'ИП владеет кофейней, есть оборудование на 3 млн ₽, кредит, персонал. Необходим комплекс страховок.', '1. Страхование имущества + ответственность арендатора.\n2. Страхование от перерыва в деятельности (бизнес-интеррапшн).\n3. Личное страхование владельца (НСЖ + ДМС).\n4. Страхование гражданской ответственности перед третьими лицами.', 14, 'medium'),
  ('case-family-finplan', 'Финплан семьи на 10 лет', 'Разработайте комплексный финансовый план.', 'Цели: обучение ребёнка (через 5 лет 1,2 млн ₽), новая квартира (через 8 лет 6 млн ₽), пенсия (через 25 лет 25 млн ₽). Доход 280 тыс ₽, сбережения 1 млн ₽. Риск — умеренный.', '1. Финансовая подушка 6 месяцев.\n2. Инвестпортфель: 50% акции, 30% облигации, 10% золото, 10% наличность.\n3. Цели разбиваются на субпортфели, используются ИИС и накопительное страхование.\n4. Годовой пересмотр плана.', 20, 'hard'),
  ('case-entrepreneur-cashflow', 'Cash-flow кафе', 'Сбалансируйте денежные потоки кофейни.', 'Кофейня с выручкой 1,4 млн ₽, переменные расходы 45%, постоянные 350 тыс ₽, кредиты 120 тыс ₽. Есть кассовые разрывы.', '1. Переговоры о постоплате с поставщиками.\n2. Внедрение программ лояльности для увеличения оборота.\n3. Оптимизация фонда оплаты труда (внедрение KPI, гибкие графики).\n4. Резерв кассы на 2 недели.', 16, 'medium'),
  ('case-insurance-payout', 'Выплата по страховке', 'Рассчитайте сумму возмещения.', 'Квартира застрахована на 4 млн ₽. Пожар повредил ремонт на 600 тыс ₽. Франшиза 5%, коэффициент износа 0,2. Определите выплату.', 'Страховая выплата = (600 000 × (1 - 0,2)) - 5% = 456 000 ₽ - 30 000 ₽ = 426 000 ₽.', 8, 'easy'),
  ('case-credit-schedule', 'График ипотеки', 'Постройте график платежей и оцените переплату.', 'Ипотека 5,5 млн ₽ на 20 лет под 8%. Найдите ежемесячный платёж и суммарную переплату.', 'Платёж ≈ 46 000 ₽. Переплата ≈ 5,6 млн ₽. Используйте формулу аннуитета.', 10, 'medium'),
  ('case-tax-entrepreneur', 'Налоги для ИП', 'Выберите оптимальный режим налогообложения.', 'ИП оказывает услуги, выручка 5 млн ₽, расходы 1,2 млн ₽, сотрудников нет. Рассмотрите УСН 6%, УСН 15%, НПД.', 'Сравнение: УСН 6% = 300 000 ₽, УСН 15% = 570 000 ₽ (плюс взносы), НПД недоступен (превышен лимит 2,4 млн). Вывод: УСН 6% выгоднее.', 9, 'easy'),
  ('case-invest-diversification', 'Диверсификация портфеля', 'Рассчитайте доли активов после роста акций.', 'Портфель: 60% акции, 30% облигации, 10% золото. Акции выросли на 25%, облигации на 5%, золото -2%. Продумайте ребалансировку.', 'Новые доли: акции ~66%, облигации ~29%, золото ~5%. Продаём часть акций, докупаем золото и облигации для возврата к целевым долям.', 11, 'medium'),
  ('case-budget-student', 'Бюджет студента', 'Оптимизация расходов первокурсника.', 'Доход 35 000 ₽ (подработка + родители). Расходы: жильё 18 000 ₽, питание 9 000 ₽, проезд 2 000 ₽, развлечения 7 000 ₽. Создайте план накоплений на ноутбук (60 000 ₽ за 6 месяцев).', 'Экономия: жильё (поиск соседей) -3 000 ₽, питание -1 500 ₽ (планирование меню), развлечения -2 500 ₽. Итог: высвобождается 7 000 ₽/мес + 3 000 ₽ за счёт дополнительной подработки → цель достигнута.', 7, 'easy'),
  ('case-insurance-travel', 'Путешествие за границу', 'Подберите комплекс страховок и бюджет.', 'Семья из четырёх человек едет на 14 дней в Европу. Определите бюджет, страховки, резервные средства.', 'Бюджет: перелёт 180 000 ₽, проживание 210 000 ₽, питание 120 000 ₽, развлечения 80 000 ₽, страховка 18 000 ₽, резерв 50 000 ₽. Страховки: медицинская, отмена поездки, страхование багажа.', 9, 'medium'),
  ('case-olympiad-team', 'Командный проект к олимпиаде', 'Постройте дорожную карту подготовки.', 'Команда из 4 человек готовится к финалу олимпиады через 3 месяца. Нужен план занятий, распределение ролей, контроль прогресса.', '1. Анализ заданий прошлых лет.\n2. Состав команды (аналитик, лидер, дизайнер, презентатор).\n3. Еженедельные спринты, ретроспективы.\n4. Финальный прогон презентации.', 12, 'medium'),
  ('case-corporate-benefits', 'Корпоративные льготы', 'Оцените пакет льгот для сотрудников банка.', 'Банк предлагает: ДМС, ипотека по сниженной ставке, НСЖ, курсы. Рассчитайте экономию сотрудника.', '1. Сравнение стоимости ДМС — 70 000 ₽ на рынке vs 0 ₽.\n2. Ипотека 6% вместо 8% → экономия 1,2 млн ₽ за срок.\n3. Курсы — 60 000 ₽ в год.\n4. Общая ценность пакета льгот > 1,3 млн ₽.', 10, 'medium'),
  ('case-fintech-product', 'Финтех-продукт для школьников', 'Разработайте MVP', 'Нужно создать цифровой продукт, обучающий школьников финансовой грамотности. Определите функционал, монетизацию, KPI.', 'MVP: карточки, симулятор бюджета, задания. Монетизация: freemium + партнёрские программы. KPI: дневная активность, процент завершённых курсов, NPS.', 13, 'hard'),
  ('case-tax-nonresident', 'Налоги нерезидента', 'Рассчитать налоговую нагрузку.', 'Илья работал в РФ 150 дней и получил доход 1,5 млн ₽. Рассчитайте НДФЛ и опишите возможность вернуть статус резидента.', 'Как нерезидент платит 30% НДФЛ → 450 000 ₽. Чтобы вернуть 13%, нужно провести в РФ ≥183 дней в году и подать заявление в ФНС.', 8, 'medium'),
  ('case-insurance-risk', 'Оценка страховых рисков', 'Проведите анализ рисков для фермерского хозяйства.', 'Ферма выращивает зерно, риски: погода, пожар, болезни, колебания цен. Предложите страховые инструменты.', '1. Страхование урожая, ответственности и имущества.\n2. Хеджирование цен фьючерсами.\n3. Создание резервного фонда.\n4. Страхование ответственности перед третьими лицами.', 14, 'hard'),
  ('case-invest-isa', 'ИИС: выбор типа вычета', 'Определите выгодный тип вычета.', 'Доход Анны по НДФЛ — 780 000 ₽, планирует пополнить ИИС на 400 000 ₽ ежегодно, горизонт 4 года. Какой тип вычета выбрать?', 'Тип А → возврат 52 000 ₽ в год, суммарно 208 000 ₽. Тип Б освобождает прибыль. Если доходность > 17% годовых, тип Б может быть выгоднее. Выбор зависит от фактической доходности.', 9, 'medium');

-- Дополнение: генерация 150 дополнительных кейсов
do $$
declare
  case_topics text[] := array['Бюджет', 'Инвестиции', 'Страхование', 'Кредитование', 'Олимпиады', 'Предпринимательство'];
  case_diff text[] := array['easy', 'medium', 'hard'];
  i int;
  topic text;
  diff text;
  ident text;
begin
  for i in 1..150 loop
    topic := case_topics[1 + (i - 1) % array_length(case_topics)];
    diff := case_diff[1 + (i - 1) % array_length(case_diff)];
    ident := format('case-auto-%s', lpad(i::text, 3, '0'));
    insert into practice_cases (id, title, summary, prompt, solution, points, difficulty, created_at)
    values (
      ident,
      format('%s: расширенный сценарий #%s', topic, lpad(i::text, 3, '0')),
      format('Работа с кейсом по тематике %s.', topic),
      format('Сформулируйте план действий и рассчитайте ключевые показатели для кейса #%s (%s).', i, topic),
      format('### Решение\n1. Анализ исходных данных\n2. Расчёт KPI\n3. Выводы и рекомендации\n\nСложность: %s.', diff),
      8 + (i % 12),
      diff,
      now() - (i || ' hours')::interval
    )
    on conflict (id) do nothing;
  end loop;
end
$$;

