-- Дополнение: события на каждый месяц ближайших трёх лет (36 записей)
do $$
declare
  base_date date := date_trunc('month', current_date);
  idx int;
  event_date date;
  status_list text[] := array['registration', 'remote', 'onsite', 'finished'];
  directions text[] := array[
    'Школьники', 'Студенты', 'Молодые специалисты', 'Наставники', 'Олимпиадники', 'Семьи'
  ];
begin
  for idx in 1..36 loop
    event_date := (base_date + (idx || ' months')::interval)::date + 10;
    insert into schedule (title, status, date, start, "end", format, direction, registration)
    values (
      format('Месячное событие #%s', lpad(idx::text, 2, '0')),
      status_list[1 + (idx - 1) % array_length(status_list)],
      event_date,
      '10:00',
      '17:00',
      case when (idx % 2 = 0) then 'Онлайн' else 'Очный' end,
      directions[1 + (idx - 1) % array_length(directions)],
      format('до %s', (event_date - 10))
    );
  end loop;
end
$$;

