------------------------------------------------------------
do $$
declare
  v_user_code constant text := 'FG-QWER-2024';
  v_user_name constant text := 'Мария';
  v_user_id uuid;
begin
  v_user_id := app.ensure_profile(v_user_code, v_user_name);

  delete from tasks where user_id = v_user_id;

  insert into tasks (user_id, title, category, status, difficulty, due_date) values
    (v_user_id, 'Сформировать личный финансовый план', 'Старт', 'todo', 'medium', current_date + 7),
    (v_user_id, 'Закрыть раздел "Налоги" в тренажёре', 'Тренажёр', 'in_progress', 'medium', current_date + 5),
    (v_user_id, 'Проработать практику "Антикризисный бюджет"', 'Практика', 'todo', 'hard', current_date + 10),
    (v_user_id, 'Обновить профиль в базе знаний', 'Администрирование', 'todo', 'easy', null),
    (v_user_id, 'Подготовиться к олимпиаде «Финансовый вызов»', 'Олимпиады', 'in_progress', 'hard', current_date + 20),
    (v_user_id, 'Создать текст для личной теории', 'Контент', 'done', 'medium', null),
    (v_user_id, 'Проверить выполнение целей за месяц', 'Аналитика', 'todo', 'medium', current_date + 14);

  -- Пример прогресса
  insert into progress (user_id, data)
  values (
    v_user_id,
    jsonb_build_object(
      'statuses', jsonb_build_object(
        '1', 'know',
        '5', 'unsure',
        '17', 'dontknow'
      ),
      'lastSeenIndex', jsonb_build_object(
        'Налоги', 12,
        'Инвестиции', 7
      )
    )
  )
  on conflict (user_id) do update set data = excluded.data;
end $$;

